function parseHexColor(input){ if(!input) return null; const raw=String(input).trim(); const hex=raw.startsWith('#')?raw.slice(1):raw; if(!/^[0-9a-fA-F]{6}$/.test(hex)) return null; const int=parseInt(hex,16); return { r:(int>>16)&255,g:(int>>8)&255,b:int&255,hex:`#${hex.toLowerCase()}`}; }
