function applyCssVariables(palette, mode){ const root=document.documentElement; const accentHex=parseHexColor((palette.accent||'#1d9bf0').replace('#','')) || parseHexColor('1d9bf0'); const vars={ '--bg-primary':palette.bgPrimary,'--bg-secondary':palette.bgSecondary,'--bg-hover':palette.bgHover,'--text-primary':palette.textPrimary,'--text-secondary':palette.textSecondary,'--border-color':palette.borderColor,'--accent-color':palette.accent,'--accent-hover':palette.accentHover||palette.accent,'--accent-color-alpha':rgbaColor(accentHex, mode==='dark'?0.35:0.25),'--accent-soft':rgbaColor(accentHex, mode==='dark'?0.16:0.12),'--accent-soft-strong':rgbaColor(accentHex, mode==='dark'?0.28:0.2),'--warning-color':palette.warning||DEFAULT_LIGHT.warning,'--danger-color':palette.danger||DEFAULT_LIGHT.danger,'--success-color':palette.success||DEFAULT_LIGHT.success,'--search-highlight-color':rgbaColor(accentHex, mode==='dark'?0.35:0.2)}; Object.entries(vars).forEach(([k,v])=>root.style.setProperty(k,v)); }
function applyThemeState(nextTheme, options={}){ const themeName=normalizeThemeName(nextTheme?.theme||'default'); const tint=nextTheme?.tint?String(nextTheme.tint).trim():null; currentTheme={theme:themeName,tint}; currentMode=resolveModeForPreset(resolvePreset(themeName)); const root=document.documentElement; root.dataset.theme=currentMode; root.dataset.colorTheme=themeName; root.dataset.tint=tint||''; root.style.colorScheme=currentMode; if(currentMode==='dark'){root.classList.add('dark'); root.classList.remove('light');} else {root.classList.add('light'); root.classList.remove('dark');} let palette = resolvePalette(themeName,currentMode); if(themeName==='default' && tint) palette = buildTintedPalette(palette,tint); applyCssVariables(palette,currentMode); if(options.persist!==false){ setLocalStorageItem(THEME_STORAGE_KEY, themeName); setLocalStorageItem(TINT_STORAGE_KEY, tint||''); } window.dispatchEvent(new CustomEvent('piclaw-theme-change',{detail:{...currentTheme,mode:currentMode}})); }
function handleSystemThemeChange(){ if(resolvePreset(currentTheme.theme).mode!=='auto') return; applyThemeState(currentTheme,{persist:false}); }
