export function cycleThemePreset(){ const names=Object.keys(THEME_PRESETS); const currentIndex=names.indexOf(currentTheme.theme); const next=names[(currentIndex+1)%names.length]||'default'; applyThemeState({theme:next,tint:currentTheme.tint},{persist:true}); return next; }
export function cycleTint(){ const currentIndex=TINTS.findIndex((t)=>t===currentTheme.tint); const next=TINTS[(currentIndex+1)%TINTS.length]; applyThemeState({theme:currentTheme.theme,tint:next},{persist:true}); return next; }
export function getCurrentThemeLabel(){ return resolvePreset(currentTheme.theme).label; }
export function getCurrentTintLabel(){ return currentTheme.tint || 'off'; }
